sudo apt update #Updates the package list from the configured repositories so the system knows which software versions are available.
sudo apt upgrade #Installs the newest available versions of the packages already installed on the system without removing packages unnecessarily.
sudo apt install parted #Downloads and installs parted, a disk partition management tool used to create, delete, resize, and manage partitions.
sudo parted -l && echo -e "\n---\n" && lsblk -f && echo -e #shows detailed information about all detected disks and their partition tables. && means the next command will only run if the previous one succeeds. echo -e "\n--\n" prints blank lines and a separator to make the output easier to read. lsblk -f displays the storage devices in a tree structure along with filesystem information such as type, label, UUID, and mount point. The final echo -e "\n---\n" prints another separator. Overall, the command is used to inspect disks and partitions in an organized way.
lsblk -f #is used to display block devices and show filesystem information for each one, such as the filesystem type, label, UUID, and mount point. It helps you identify disks, partitions, and where they are mounted in the system.
